/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — MobileTabBar
   5-tab iOS bottom navigation: Home, Positions, Signals, Research, Account
   Active tab: green (#3FB950). Inactive: grey (#8B949E).
   Red badge on Signals tab when new signals arrive.
   Safe area padding for iPhone notch / home indicator.
   Hides when keyboard is open.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useCallback } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useTheme } from '../contexts/ThemeContext';

// ── SVG Icons (stroke style, 24x24 viewBox) ──────────────────────────────
const TabIcons = {
  home: (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <rect x="3" y="3" width="7" height="7" rx="1.5" />
      <rect x="14" y="3" width="7" height="7" rx="1.5" />
      <rect x="3" y="14" width="7" height="7" rx="1.5" />
      <rect x="14" y="14" width="7" height="7" rx="1.5" />
    </svg>
  ),
  positions: (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <rect x="2" y="4" width="20" height="16" rx="2" />
      <path d="M2 10h20" />
      <path d="M6 15h4" />
      <path d="M14 15h4" />
    </svg>
  ),
  signals: (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <path d="M13 2L4.5 12.5h5.5l-1.5 9.5 9-11h-6z" />
    </svg>
  ),
  research: (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <path d="M3 3v18h18" />
      <path d="M7 16l4-6 4 3 5-7" />
    </svg>
  ),
  account: (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="12" cy="8" r="4" />
      <path d="M5 21c0-4 3.5-7 7-7s7 3 7 7" />
    </svg>
  ),
};

// ── Tab definitions ──────────────────────────────────────────────────────
const TABS = [
  { id: 'home',      label: 'Home',      icon: TabIcons.home,      path: '/mobile-home' },
  { id: 'positions', label: 'Positions',  icon: TabIcons.positions, path: '/mobile-positions' },
  { id: 'signals',   label: 'Signals',    icon: TabIcons.signals,   path: '/mobile-signals' },
  { id: 'research',  label: 'Research',   icon: TabIcons.research,  path: '/mobile-research' },
  { id: 'account',   label: 'Account',    icon: TabIcons.account,   path: '/mobile-account' },
];

// ── Match current path to active tab ────────────────────────────────────
function getActiveTab(pathname) {
  if (pathname === '/mobile-home' || pathname === '/' || pathname === '/home' || pathname === '/trader/command') return 'home';
  if (pathname === '/mobile-signals' || pathname.startsWith('/mobile-signals')) return 'signals';
  if (pathname === '/mobile-positions' || pathname.startsWith('/positions') || pathname.startsWith('/orders') || pathname.startsWith('/portfolio')) return 'positions';
  if (pathname === '/mobile-research' || pathname.startsWith('/strategies') || pathname.startsWith('/scanners') || pathname.startsWith('/charts')) return 'research';
  if (pathname === '/mobile-account' || pathname.startsWith('/profile') || pathname.startsWith('/appearance') || pathname.startsWith('/notifications') || pathname.startsWith('/billing')) return 'account';
  return 'home';
}

// ═══════════════════════════════════════════════════════════════════════════
export default function MobileTabBar({ signalBadgeCount = 0 }) {
  const navigate = useNavigate();
  const location = useLocation();
  const { colors } = useTheme();
  const [keyboardVisible, setKeyboardVisible] = useState(false);

  const activeTab = getActiveTab(location.pathname);

  // ── Detect keyboard open/close via viewport resize ──────────────────
  useEffect(() => {
    if (!window.visualViewport) return;
    const vv = window.visualViewport;
    const onResize = () => {
      // If viewport height drops significantly, keyboard is likely open
      const threshold = window.innerHeight * 0.75;
      setKeyboardVisible(vv.height < threshold);
    };
    vv.addEventListener('resize', onResize);
    return () => vv.removeEventListener('resize', onResize);
  }, []);

  const handleTabPress = useCallback((tab) => {
    navigate(tab.path);
  }, [navigate]);

  // Hide the tab bar when keyboard is visible
  if (keyboardVisible) return null;

  // ── Colors ────────────────────────────────────────────────────────────
  const activeColor = '#3FB950';
  const inactiveColor = '#8B949E';
  const bgColor = colors?.surface || '#161B22';
  const borderColor = colors?.border || 'rgba(255,255,255,0.06)';

  return (
    <nav
      style={{
        position: 'fixed',
        bottom: 0,
        left: 0,
        right: 0,
        zIndex: 9999,
        background: bgColor,
        borderTop: `1px solid ${borderColor}`,
        display: 'flex',
        alignItems: 'stretch',
        justifyContent: 'space-around',
        paddingBottom: 'env(safe-area-inset-bottom, 0px)',
        paddingTop: 6,
        backdropFilter: 'blur(20px)',
        WebkitBackdropFilter: 'blur(20px)',
        fontFamily: "system-ui, -apple-system, sans-serif",
      }}
      role="tablist"
      aria-label="Main navigation"
    >
      {TABS.map((tab) => {
        const isActive = activeTab === tab.id;
        const color = isActive ? activeColor : inactiveColor;

        return (
          <button
            key={tab.id}
            role="tab"
            aria-selected={isActive}
            aria-label={tab.label}
            onClick={() => handleTabPress(tab)}
            style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              gap: 2,
              flex: 1,
              minHeight: 50,
              minWidth: 44,
              padding: '4px 0 6px',
              background: 'none',
              border: 'none',
              cursor: 'pointer',
              color,
              position: 'relative',
              WebkitTapHighlightColor: 'transparent',
              transition: 'color 200ms ease',
            }}
          >
            {/* Icon */}
            <span style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative' }}>
              {tab.icon}
              {/* Red signal badge */}
              {tab.id === 'signals' && signalBadgeCount > 0 && (
                <span
                  style={{
                    position: 'absolute',
                    top: -4,
                    right: -8,
                    minWidth: 16,
                    height: 16,
                    borderRadius: 8,
                    background: '#F85149',
                    color: '#FFFFFF',
                    fontSize: 9,
                    fontWeight: 700,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    padding: '0 4px',
                    lineHeight: 1,
                  }}
                >
                  {signalBadgeCount > 9 ? '9+' : signalBadgeCount}
                </span>
              )}
            </span>

            {/* Label */}
            <span
              style={{
                fontSize: 10,
                fontWeight: isActive ? 600 : 500,
                letterSpacing: '0.01em',
                lineHeight: 1,
              }}
            >
              {tab.label}
            </span>
          </button>
        );
      })}
    </nav>
  );
}

// Export for route matching in other components
export { TABS, getActiveTab };
